#!/usr/bin/env bash
# GENERATED by `ggen sync` from packs/ggen-verify-pack (verify_evidence_sh.tmpl).
# Evidence emitter for the self-hosted verification loop: runs every
# ver:RequiredCheck projected from the union graph (name + ver:checkCommand
# are ontology facts, not hand-maintained here) and records the REAL exit
# codes as ver:Check facts in evidence/ontology.ttl -- the local
# `verify-evidence` mini-pack the consumer wires in [packs].
#
# This script ALWAYS exits 0: it records reality, it does not judge it.
# Judgment belongs to packs/ggen-verify-pack/gates/*.rq at the next
# `ggen sync run` -- red, missing, or stale evidence there is an
# FM-PACK-013 refusal. That split (emit facts / gate facts) is the point.
#
# Bootstrap note: on a fresh consumer this file does not exist yet (it is
# generated by the very sync the gates protect). Run the committed copy
# once instead: bash packs/ggen-verify-pack/bootstrap/verify-evidence-bootstrap.sh
# (see packs/ggen-verify-pack/README.md, "Two-phase bootstrap").
set -uo pipefail

cd "$(dirname "$0")/.."
mkdir -p evidence evidence/templates

RECORDED_AT="$(date -u +%Y-%m-%dT%H:%M:%SZ)"

# --- graph-hash binding (freshness gate 030) --------------------------------
# Bind this evidence to the latest completed sync's graph hash. On a
# never-synced tree there is no receipt yet; record "unsynced" (the
# freshness gate only fires when a ggenr:Sync fact exists to disagree with).
GRAPH_HASH="unsynced"
if [ -f .ggen-v2/receipt.json ]; then
  GRAPH_HASH="$(python3 -c 'import json;print(json.load(open(".ggen-v2/receipt.json"))["payload"]["graph_hash"])' 2>/dev/null || echo unsynced)"
fi

# --- run every required check, capturing REAL exit codes --------------------
CHECK_NAMES=(); CHECK_CODES=(); CHECK_TOOLS=(); CHECK_SUMMARIES=()
run_check() { # name, command-string (run via bash -c from the consumer root)
  local name="$1" cmd="$2"
  local log="${TMPDIR:-/tmp}/verify-evidence-$name-$$.log"
  bash -c "$cmd" >"$log" 2>&1
  local code=$?
  CHECK_NAMES+=("$name")
  CHECK_CODES+=("$code")
  CHECK_TOOLS+=("$cmd")
  CHECK_SUMMARIES+=("$(tail -1 "$log" | tr '"' "'" | cut -c1-200)")
  rm -f "$log"
}

run_check 'build' 'cargo build --workspace'
run_check 'byte-identity' 'bash scripts/checks/byte-identity.sh'
run_check 'clippy-reference-gate' 'cargo clippy --workspace --all-targets -- -D clippy::correctness -D clippy::suspicious -D clippy::perf'
run_check 'test-workspace' 'cargo test --workspace'

# --- scaffold the evidence mini-pack on first run ---------------------------
# The evidence enters the graph through the same pack-admission path as
# every other governing input: a local pack (`verify-evidence = { path =
# "evidence" }` in the consumer's [packs]). pack.toml and the one required
# template (FM-PACK-005: a pack must ship >=1 template) are written only if
# absent; ontology.ttl is regenerated on every run.
if [ ! -f evidence/pack.toml ]; then
  cat > evidence/pack.toml <<'EOF'
[pack]
name = "verify-evidence"
version = "0.0.0"
description = "GENERATED verification evidence (ver: facts) emitted by scripts/verify-evidence.sh (ggen-verify-pack); admitted into the union graph so ggen-verify-pack's gates can enforce it. Never hand-edited."
EOF
fi
if [ ! -f evidence/templates/evidence_note.md.tmpl ]; then
  cat > evidence/templates/evidence_note.md.tmpl <<'EOF'
---
to: receipts/EVIDENCE_NOTE.md
---
# Verification evidence admitted

This consumer's `evidence/ontology.ttl` (ver:Check facts with real exit
codes, regenerated by `scripts/verify-evidence.sh`) is part of the union
graph. This file rendering at all means the evidence was admitted and
ggen-verify-pack's gates passed on the last sync.
EOF
fi

# --- emit evidence/ontology.ttl ---------------------------------------------
{
  echo "# GENERATED by scripts/verify-evidence.sh at $RECORDED_AT -- do not edit."
  echo "# Real exit codes from real command runs; gated by ggen-verify-pack."
  echo "@prefix ver: <http://seanchatmangpt.github.io/packs/ggen-verify#> ."
  echo
  for i in "${!CHECK_NAMES[@]}"; do
    n="${CHECK_NAMES[$i]}"
    echo "ver:check-$n a ver:Check ;"
    echo "    ver:name \"$n\" ;"
    echo "    ver:tool \"${CHECK_TOOLS[$i]}\" ;"
    echo "    ver:exitCode ${CHECK_CODES[$i]} ;"
    echo "    ver:summary \"${CHECK_SUMMARIES[$i]}\" ;"
    echo "    ver:verifiedGraphHash \"$GRAPH_HASH\" ;"
    echo "    ver:recordedAt \"$RECORDED_AT\" ."
    echo
  done
} > evidence/ontology.ttl

echo "verify-evidence.sh: recorded ${#CHECK_NAMES[@]} checks -> evidence/ontology.ttl (graph hash binding: $GRAPH_HASH)"
for i in "${!CHECK_NAMES[@]}"; do
  echo "  ${CHECK_NAMES[$i]}: exit ${CHECK_CODES[$i]}"
done
exit 0

